def store_info_in_header(info_type: str, info_content: str, header: Dict[str, str]) -> Dict[str, str]:
    if info_type not in ['lang', 'encoding', 'cache']:
        return header
    mapping = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }
    key = mapping[info_type]
    header[key] = info_content
    return header

